// constants
const faqs = [
  {
    question: "Why Must I Make Payment Immediately At Checkout?",
    answer:
      "Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  },
  {
    question: "What Happens if There's Been A Delivery Mishap To My Order?",
    answer:
      "Because you are important to us, we want to know what you think about the products. As an added value, every time you rate the products you earn points."
  },
  {
    question:
      "How Long Will It Take For My Order To Arrive After I Make Payment?",
    answer:
      "Due to the limited quantity, each member's account is only entitled to 1 unique free sample. You can check out up to 4 free samples in each checkout."
  }
];

//  ------------------------------ | FAQ - 6 | ------------------------------  //

export default function Faq6() {
  return (
    <section className="py-20 md:py-28">
      <div className="container mx-auto px-4">
        {/* Header */}
        <div className="mx-auto mb-16 max-w-sm text-center">
          <h2 className="mb-6">Frequently Asked Questions</h2>
          <p className="text-muted-foreground">
            This is a big one and i consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* Grid */}
        <div className="grid grid-cols-12 gap-6">
          {faqs.map((item, index) => (
            <div key={index} className="col-span-12 md:col-span-4">
              <div className="flex flex-col gap-3">
                {/* Question */}
                <div className="min-h-16">
                  <h5>{item.question}</h5>
                </div>
                {/* Divider */}
                <div className="h-0.5 w-full bg-primary" />
                {/* Answer */}
                <p className="text-muted-foreground">{item.answer}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
